import React, { useEffect, useMemo, useState } from 'react';
import { View, Text, Button, StyleSheet, FlatList, TouchableOpacity, Alert } from 'react-native';

const TOKEN_PREFIX = 'local';
const TOKEN_LENGTH = 24;
const TOKEN_TTL_MS = 1000 * 60 * 60 * 24;

function randomTokenString(length = TOKEN_LENGTH) {
  const chars = 'abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789';
  let out = '';
  for (let i = 0; i < length; i += 1) {
    out += chars.charAt(Math.floor(Math.random() * chars.length));
  }
  return out;
}

function createLocalSessionToken() {
  const now = Date.now();
  return {
    id: `${TOKEN_PREFIX}_${now}_${randomTokenString(12)}`,
    token: `${TOKEN_PREFIX}_${randomTokenString()}`,
    createdAt: now,
    expiresAt: now + TOKEN_TTL_MS,
    synced: false,
  };
}

function isTokenExpired(token) {
  return Date.now() > token.expiresAt;
}

export default function OfflineTokenGenerator() {
  const [online, setOnline] = useState(false);
  const [tokens, setTokens] = useState([]);

  const activeTokens = useMemo(() => tokens.filter((t) => !isTokenExpired(t)), [tokens]);

  useEffect(() => {
    const interval = setInterval(() => {
      setTokens((prev) => prev.filter((t) => !isTokenExpired(t)));
    }, 30000);
    return () => clearInterval(interval);
  }, []);

  const generateToken = () => {
    if (online) {
      Alert.alert('Online', 'Local session tokens are intended for offline mode.');
      return;
    }
    const token = createLocalSessionToken();
    setTokens((prev) => [token, ...prev]);
  };

  const toggleConnectivity = () => {
    setOnline((prev) => !prev);
  };

  const markSynced = (id) => {
    setTokens((prev) =>
      prev.map((t) => (t.id === id ? { ...t, synced: true } : t))
    );
  };

  const removeToken = (id) => {
    setTokens((prev) => prev.filter((t) => t.id !== id));
  };

  return (
    <View style={styles.container}>
      <Text style={styles.title}>Offline Token Generator</Text>
      <Text style={[styles.status, online ? styles.online : styles.offline]}>
        Status: {online ? 'Online' : 'Offline'}
      </Text>

      <View style={styles.actions}>
        <Button title={online ? 'Go Offline' : 'Go Online'} onPress={toggleConnectivity} />
        <View style={styles.spacer} />
        <Button title="Generate Local Token" onPress={generateToken} />
      </View>

      <Text style={styles.subtitle}>Active Tokens ({activeTokens.length})</Text>

      <FlatList
        data={activeTokens}
        keyExtractor={(item) => item.id}
        ListEmptyComponent={<Text style={styles.empty}>No local tokens generated.</Text>}
        renderItem={({ item }) => (
          <View style={styles.card}>
            <Text style={styles.tokenLabel}>Token</Text>
            <Text style={styles.tokenValue}>{item.token}</Text>
            <Text style={styles.meta}>Created: {new Date(item.createdAt).toLocaleString()}</Text>
            <Text style={styles.meta}>Expires: {new Date(item.expiresAt).toLocaleString()}</Text>
            <Text style={styles.meta}>Synced: {item.synced ? 'Yes' : 'No'}</Text>

            <View style={styles.cardActions}>
              <TouchableOpacity style={styles.cardButton} onPress={() => markSynced(item.id)}>
                <Text style={styles.cardButtonText}>Mark Synced</Text>
              </TouchableOpacity>
              <TouchableOpacity style={[styles.cardButton, styles.deleteButton]} onPress={() => removeToken(item.id)}>
                <Text style={styles.cardButtonText}>Delete</Text>
              </TouchableOpacity>
            </View>
          </View>
        )}
      />
    </View>
  );
}

